class Solution {
public:
    char kthCharacter(long long k, vector<int>& operations) {
        long long length = 1;
        for (int op : operations) {
            if (op == 0) {
                length *= 2;
            } else {
                length *= 2;
            }
        }
        for (int i = operations.size() - 1; i >= 0; --i) {
            if (k > length / 2) {
                k -= length / 2;
                if (operations[i] == 1) {
                    k %= length / 2;
                    if (k == 0) k = length / 2;
                }
            }
            length /= 2;
        }
        return 'a' + (k - 1) % 26;
    }
};
